 1→export function signedPolygonArea(points) {
 2→  let area = 0;
 3→  const n = points.length;
 4→  for (let i = 0; i < n; i++) {
 5→    const j = (i + 1) % n;
 6→    area += points[i].x * points[j].y;
 7→    area -= points[j].x * points[i].y;
 8→  }
 9→  return area / 2;
10→}
